import (
	accountadapter "github.com/openmeterio/openmeter/openmeter/ledger/account/adapter"
	accountservice "github.com/openmeterio/openmeter/openmeter/ledger/account/service"
	"github.com/openmeterio/openmeter/openmeter/ledger/resolvers"
	resolversadapter "github.com/openmeterio/openmeter/openmeter/ledger/resolvers/adapter"
	"github.com/openmeterio/openmeter/pkg/framework/lockr"
)

func newService() (*ledgerbackfillservice.Service, error) {
	locker, err := lockr.NewLocker(&lockr.LockerConfig{Logger: internal.App.Logger})
	if err != nil { return nil, fmt.Errorf("create locker: %w", err) }
	accountRepo := accountadapter.NewRepo(internal.App.EntClient)
	accountSvc := accountservice.New(accountRepo, locker)
	resolverRepo := resolversadapter.NewRepo(internal.App.EntClient)
	accountResolver := resolvers.NewAccountResolver(resolvers.AccountResolverConfig{
		AccountService: accountSvc, Repo: resolverRepo, Locker: locker,
	})
	return ledgerbackfillservice.NewService(ledgerbackfillservice.Config{
		CustomerLister:     ledgerbackfillservice.NewEntCustomerLister(internal.App.EntClient),
		AccountProvisioner: accountResolver,
		Logger:             internal.App.Logger,
	})
}

import (
	"github.com/openmeterio/openmeter/openmeter/ledger"
	"github.com/openmeterio/openmeter/pkg/models"
	paginationv2 "github.com/openmeterio/openmeter/pkg/pagination/v2"
)

var cursor *paginationv2.Cursor
completed := false
for iter := 0; iter < paginationv2.MAX_SAFE_ITER; iter++ {
	res, err := s.customerLister.ListCustomers(ctx, ListCustomersInput{Namespace: namespace, PageSize: input.CustomerPageSize, Cursor: cursor})
	if err != nil {
		failure := s.recordFailure(&result, "list_customers", "", err)
		if input.ContinueOnError { return result, nil }
		return result, failure
	}
	for _, item := range res.Items {
		result.CustomersScanned++
		if err := s.ensureCustomerAccounts(ctx, input, &result, customer.CustomerID{Namespace: namespace, ID: item.ID}); err != nil {
			if !input.ContinueOnError { return result, err }
		}
	}
	if res.NextCursor == nil { completed = true; break }
	cursor = res.NextCursor
}
if !completed {
	return result, s.recordFailure(&result, "paginate_customers", "", fmt.Errorf("max safe iter reached: %d", paginationv2.MAX_SAFE_ITER))
}
